# Simulated modernized DATAR system data aggregation
class DATARSystem:
    def __init__(self):
        self.ship_sensors = {
            'Ship_A': {'radar': 45.2, 'sonar': 32.7, 'speed': 22.1},
            'Ship_B': {'radar': 44.9, 'sonar': 33.1, 'speed': 21.8},
            'Ship_C': {'radar': 45.5, 'sonar': 32.5, 'speed': 22.3}
        }

    def aggregate_data(self):
        consolidated = {
            'average_radar': sum(s['radar'] for s in self.ship_sensors.values()) / len(self.ship_sensors),
            'average_sonar': sum(s['sonar'] for s in self.ship_sensors.values()) / len(self.ship_sensors),
            'average_speed': sum(s['speed'] for s in self.ship_sensors.values()) / len(self.ship_sensors)
        }
        return consolidated

# Usage
datar = DATARSystem()
print("Consolidated task force data:", datar.aggregate_data())
